var data = (typeof msg.payload === "string") ? JSON.parse(msg.payload) : (msg.payload || {});
var raw = data.raw || data;
var rssiVal = (data.rssi !== undefined) ? data.rssi : raw.rssi;
var snrVal = (data.snr !== undefined) ? data.snr : raw.snr;

var fields = {
    latitude: parseFloat(raw.lat) || 0.0,
    longitude: parseFloat(raw.lon) || 0.0,
    rssi: parseInt(rssiVal) || 0,
    snr: parseFloat(snrVal) || 0.0,
    battery: parseFloat(raw.battery) || 100.0,
    wake_count: parseInt(raw.wake_count) || 0
};
var tags = {
    device_id: raw.device_id || "edge-01",
    fence_status: raw.fence_status || "UNKNOWN"
};
msg.payload = [fields, tags];
return msg;

var data = msg.payload;
if (!data || data.fence_status !== 'OUTSIDE') {
    return null;
}

// Calcular distancia al centro del fence (bounding box)
var fenceMinLat = flow.get('fence_min_lat') || global.get('fence_min_lat') || -34.9250;
var fenceMaxLat = flow.get('fence_max_lat') || global.get('fence_max_lat') || -34.9150;
var fenceMinLon = flow.get('fence_min_lon') || global.get('fence_min_lon') || -57.9600;
var fenceMaxLon = flow.get('fence_max_lon') || global.get('fence_max_lon') || -57.9450;

// Centro del bounding box
var centerLat = (fenceMinLat + fenceMaxLat) / 2;
var centerLon = (fenceMinLon + fenceMaxLon) / 2;

// Haversine simplificado para distancia en metros
var R = 6378137.0;
var dLat = (data.lat - centerLat) * Math.PI / 180;
var dLon = (data.lon - centerLon) * Math.PI / 180;
var a = Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(centerLat * Math.PI / 180) * Math.cos(data.lat * Math.PI / 180) *
        Math.sin(dLon/2) * Math.sin(dLon/2);
var dist = R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));

// Distancia al borde más cercano del fence
var distToBorderLat = 0;
if (data.lat < fenceMinLat) distToBorderLat = fenceMinLat - data.lat;
else if (data.lat > fenceMaxLat) distToBorderLat = data.lat - fenceMaxLat;

var distToBorderLon = 0;
if (data.lon < fenceMinLon) distToBorderLon = fenceMinLon - data.lon;
else if (data.lon > fenceMaxLon) distToBorderLon = data.lon - fenceMaxLon;

var dLatBorder = distToBorderLat * Math.PI / 180;
var dLonBorder = distToBorderLon * Math.PI / 180;
var aBorder = Math.sin(dLatBorder/2) * Math.sin(dLatBorder/2) +
             Math.cos(data.lat * Math.PI / 180) * Math.cos(data.lat * Math.PI / 180) *
             Math.sin(dLonBorder/2) * Math.sin(dLonBorder/2);
var distBorder = R * 2 * Math.atan2(Math.sqrt(aBorder), Math.sqrt(1-aBorder));

var mapsUrl = 'https://www.google.com/maps?q=' + data.lat + ',' + data.lon;

var text = '🔴 *ALERTA DE GEOFENCE*\n\n';
text += '📛 Módulo: `' + data.device_id + '`\n';
text += '⚠️ Estado: *FUERA DEL PERÍMETRO*\n\n';
text += '📍 Ubicación actual:\n';
text += '[Ver en Google Maps](' + mapsUrl + ')\n\n';
text += '📏 Distancia al borde del fence: *' + distBorder.toFixed(1) + ' metros*\n';
text += '📏 Distancia al centro del fence: *' + dist.toFixed(1) + ' metros*\n\n';
text += '🔋 Batería: ' + (data.battery || 'N/A') + '%\n';
text += '📶 RSSI: ' + (data.rssi || 'N/A') + ' dBm | SNR: ' + (data.snr || 'N/A') + '\n';
text += '⏱️ Ciclo: #' + (data.wake_count || 0);

// CHAT_ID del usuario para alertas proactivas
var chatId = 5278783015;

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: { parse_mode: 'Markdown', disable_web_page_preview: false }
};
return msg;

// Guardar el chatId original para la respuesta
flow.set('tg_modulos_chatId', msg.originalMessage.chat.id);

// Query para obtener el último registro de cada device_id activo en las últimas 24h
msg.query = 'SELECT last("latitude") AS lat, last("longitude") AS lon FROM "cattle_position" WHERE time > now() - 24h GROUP BY "device_id"';
return msg;

var results = msg.payload;
var chatId = flow.get('tg_modulos_chatId');

if (!results || results.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '📡 No hay módulos activos en las últimas 24 horas.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

// Extraer device_ids únicos
var devices = [];
var groupResults = msg.payload;

// InfluxDB GROUP BY devuelve un array de series, cada una con tags
if (Array.isArray(groupResults)) {
    for (var i = 0; i < groupResults.length; i++) {
        var row = groupResults[i];
        var devId = '';
        // El device_id puede venir como tag en el objeto o en groupTags
        if (row.device_id) devId = row.device_id;
        else if (row.tags && row.tags.device_id) devId = row.tags.device_id;
        else if (row.name) devId = row.name;
        if (devId && devices.indexOf(devId) === -1) {
            devices.push(devId);
        }
    }
}

if (devices.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '📡 No se encontraron módulos activos.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

// Construir botones inline (un botón por módulo)
var keyboard = [];
for (var j = 0; j < devices.length; j++) {
    keyboard.push([{ text: '📍 ' + devices[j], callback_data: '/detalle_' + devices[j] }]);
}

var text = '📡 *Módulos Activos (' + devices.length + '):*\n\n';
text += 'Seleccioná un módulo para ver su ubicación y estado:';

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: {
        parse_mode: 'Markdown',
        reply_markup: JSON.stringify({ inline_keyboard: keyboard })
    }
};
return msg;

var callbackData = msg.payload.content || '';
var chatId = msg.payload.chatId;

// Extraer device_id del callback_data: '/detalle_edge-01' → 'edge-01'
if (!callbackData.startsWith('/detalle_')) {
    return null;
}
var deviceId = callbackData.replace('/detalle_', '');

// Guardar contexto para la respuesta
flow.set('tg_detalle_chatId', chatId);
flow.set('tg_detalle_deviceId', deviceId);

// Query con filtro por device_id
msg.query = 'SELECT last("latitude") AS lat, last("longitude") AS lon, last("battery") AS battery, last("rssi") AS rssi, last("snr") AS snr, last("wake_count") AS wake_count FROM "cattle_position" WHERE "device_id" = \'' + deviceId + '\' AND time > now() - 24h';
return msg;

var results = msg.payload;
var chatId = flow.get('tg_detalle_chatId');
var deviceId = flow.get('tg_detalle_deviceId');

if (!results || results.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '❌ No se encontraron datos para el módulo `' + deviceId + '`.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

var r = results[0];
var lat = r.lat || 0;
var lon = r.lon || 0;

// Evaluar geofence (bounding box)
var fenceMinLat = flow.get('fence_min_lat') || global.get('fence_min_lat') || -34.9250;
var fenceMaxLat = flow.get('fence_max_lat') || global.get('fence_max_lat') || -34.9150;
var fenceMinLon = flow.get('fence_min_lon') || global.get('fence_min_lon') || -57.9600;
var fenceMaxLon = flow.get('fence_max_lon') || global.get('fence_max_lon') || -57.9450;

var isInside = (lat >= fenceMinLat && lat <= fenceMaxLat &&
               lon >= fenceMinLon && lon <= fenceMaxLon);

var statusIcon = isInside ? '🟢' : '🔴';
var statusText = isInside ? 'DENTRO del perímetro' : 'FUERA del perímetro';

var mapsUrl = 'https://www.google.com/maps?q=' + lat + ',' + lon;

var text = '🐄 *Detalle del Módulo:* `' + deviceId + '`\n\n';
text += statusIcon + ' Estado: *' + statusText + '*\n\n';
text += '📍 Ubicación:\n';
text += '[🗺️ Ver en Google Maps](' + mapsUrl + ')\n\n';
text += '🔋 Batería: ' + (r.battery || 'N/A') + '%\n';
text += '📶 RSSI: ' + (r.rssi || 'N/A') + ' dBm\n';
text += '📶 SNR: ' + (r.snr || 'N/A') + '\n';
text += '⏱️ Último ciclo: #' + (r.wake_count || 'N/A');

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: { parse_mode: 'Markdown', disable_web_page_preview: false }
};
return msg;

var data = msg.payload;
if (data.min_lat !== undefined) { flow.set('fence_min_lat', data.min_lat); global.set('fence_min_lat', data.min_lat); }
if (data.max_lat !== undefined) { flow.set('fence_max_lat', data.max_lat); global.set('fence_max_lat', data.max_lat); }
if (data.min_lon !== undefined) { flow.set('fence_min_lon', data.min_lon); global.set('fence_min_lon', data.min_lon); }
if (data.max_lon !== undefined) { flow.set('fence_max_lon', data.max_lon); global.set('fence_max_lon', data.max_lon); }
node.status({fill:'green', shape:'dot', text:'Fence actualizado'});
return null;

var lat = flow.get('sim_lat') || -34.9205;
var lon = flow.get('sim_lon') || -57.9536;
if (msg.topic === 'lat') { flow.set('sim_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'lon') { flow.set('sim_lon', parseFloat(msg.payload)); return null; }
lat = flow.get('sim_lat') || -34.9205;
lon = flow.get('sim_lon') || -57.9536;
msg.payload = JSON.stringify({ lat: lat, lon: lon, timestamp: new Date().toISOString() });
msg.retain = true;
node.status({fill:'green', shape:'dot', text: lat.toFixed(4) + ', ' + lon.toFixed(4)});
return msg;

var min_lat = flow.get('fence_min_lat') || -34.9250;
var max_lat = flow.get('fence_max_lat') || -34.9150;
var min_lon = flow.get('fence_min_lon') || -57.9600;
var max_lon = flow.get('fence_max_lon') || -57.9450;
if (msg.topic === 'min_lat') { flow.set('fence_min_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'max_lat') { flow.set('fence_max_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'min_lon') { flow.set('fence_min_lon', parseFloat(msg.payload)); return null; }
if (msg.topic === 'max_lon') { flow.set('fence_max_lon', parseFloat(msg.payload)); return null; }
min_lat = flow.get('fence_min_lat') || -34.9250;
max_lat = flow.get('fence_max_lat') || -34.9150;
min_lon = flow.get('fence_min_lon') || -57.9600;
max_lon = flow.get('fence_max_lon') || -57.9450;
msg.payload = JSON.stringify({ min_lat: min_lat, max_lat: max_lat, min_lon: min_lon, max_lon: max_lon, timestamp: new Date().toISOString() });
msg.retain = true;
node.status({fill:'blue', shape:'dot', text:'Fence actualizado'});
return msg;

var body = msg.payload || {};
var vertices = body.vertices || [];
if (!Array.isArray(vertices) || vertices.length < 3) {
    msg.payload = { status: "error", message: "Polígono inválido: mínimo 3 vértices requeridos." };
    msg.statusCode = 400;
    return [null, msg];
}
var min_lat = vertices[0].lat, max_lat = vertices[0].lat;
var min_lon = vertices[0].lon, max_lon = vertices[0].lon;
for (var i = 1; i < vertices.length; i++) {
    if (vertices[i].lat < min_lat) min_lat = vertices[i].lat;
    if (vertices[i].lat > max_lat) max_lat = vertices[i].lat;
    if (vertices[i].lon < min_lon) min_lon = vertices[i].lon;
    if (vertices[i].lon > max_lon) max_lon = vertices[i].lon;
}
var esp32Payload = {
    min_lat: Number(min_lat.toFixed(6)),
    max_lat: Number(max_lat.toFixed(6)),
    min_lon: Number(min_lon.toFixed(6)),
    max_lon: Number(max_lon.toFixed(6))
};
var mqttMsg = {
    topic: "geofence/config_update",
    payload: JSON.stringify(esp32Payload),
    qos: 1,
    retain: true
};
msg.statusCode = 200;
msg.payload = {
    status: "success",
    message: "Geofence actualizado con " + vertices.length + " vértices y publicado por MQTT.",
    topic: "geofence/config_update",
    timestamp: Math.floor(Date.now() / 1000)
};
return [mqttMsg, msg];
